import{_ as l,C as i,o as t,c as r,j as a,a as d,E as s,a2 as n}from"./chunks/framework.Bj6f68Cg.js";const h=JSON.parse('{"title":"Live LLM Demo","description":"GCP API Gateway와 GoVail 정책 경계를 통과하는 사설 LLM을 직접 체험합니다.","frontmatter":{"title":"Live LLM Demo","description":"GCP API Gateway와 GoVail 정책 경계를 통과하는 사설 LLM을 직접 체험합니다.","aside":false,"outline":false},"headers":[],"relativePath":"live-demo.md","filePath":"live-demo.md"}'),m={name:"live-demo.md"};function c(p,e,L,f,P,_){const o=i("LiveLlmDemo");return t(),r("div",null,[e[0]||(e[0]=a("h1",{id:"ai-platform-live-lab",tabindex:"-1"},[d("AI Platform Live Lab "),a("a",{class:"header-anchor",href:"#ai-platform-live-lab","aria-label":'Permalink to "AI Platform Live Lab"'},"​")],-1)),e[1]||(e[1]=a("p",null,"첫 화면과 동일한 실전형 분석 환경입니다. 아키텍처 검토, 장애 분석, 보안 검토 또는 직접 입력한 질문을 실제 사설 LLM 경로에서 실행합니다.",-1)),s(o),e[2]||(e[2]=n('<h2 id="이-요청에서-검증되는-것" tabindex="-1">이 요청에서 검증되는 것 <a class="header-anchor" href="#이-요청에서-검증되는-것" aria-label="Permalink to &quot;이 요청에서 검증되는 것&quot;">​</a></h2><ol><li>GCP API Gateway가 외부 요청을 단일 공개 경로로 받습니다.</li><li>GoVail Gateway가 SurrealDB의 Key Hash로 <code>portfolio-demo</code> 프로젝트를 식별합니다.</li><li>요청 빈도, 허용 모델, 입력 크기, DLP와 Prompt Policy를 검사합니다.</li><li>LiteLLM이 <code>auto</code> 별칭을 실제 추론 Backend로 라우팅합니다.</li><li>요청 상태와 지연시간을 내부 감사 이벤트로 남겨 운영 경로를 재현할 수 있게 합니다.</li></ol><p>모델은 요청을 내부에서 분석합니다. 원문 추론 과정은 공개하지 않고, 최종 답변만 입력 영역 옆 결과 패널에 표시합니다.</p><p>응답을 기다리는 동안에는 확인할 사실, 부족한 근거와 검토 기준을 공개용 메모로 보여줍니다. 이 메모만 현재 브라우저 탭의 <code>sessionStorage</code>에 보관하며 원문 프롬프트, 최종 답변과 모델의 원문 추론은 저장하지 않습니다.</p><h2 id="공개-체험의-경계" tabindex="-1">공개 체험의 경계 <a class="header-anchor" href="#공개-체험의-경계" aria-label="Permalink to &quot;공개 체험의 경계&quot;">​</a></h2><ul><li>체험 Key는 <code>portfolio-demo</code> 프로젝트와 <code>auto</code> 모델에만 사용할 수 있습니다.</li><li>안정적인 체험을 위해 요청 빈도와 입력 규모를 운영 정책으로 제어합니다.</li><li>프롬프트와 답변 원문은 포트폴리오 방문 분석 목적으로 저장하지 않습니다.</li><li>운영 상태나 자원 예산에 따라 체험이 일시적으로 중지될 수 있습니다.</li><li>이 환경은 서비스 SLA를 제공하는 공개 API가 아니라 아키텍처 검증용 Demo입니다.</li></ul><p>상세 설계와 보안 판단은 <a href="/projects/ai-gateway-infra-demo">AI Gateway Infra Demo</a>와 <a href="/projects/aegis-llm">Aegis-LLM</a>에서 확인할 수 있습니다.</p>',7))])}const v=l(m,[["render",c]]);export{h as __pageData,v as default};
